const matches = ALL_TOOLS.filter(x =>
  /openai.*docs|developer.*docs|api.key/i.test(x.name + " " + x.description)
);
text(matches);

const [docs, latest, spec, repo] = await Promise.all([
  tools.mcp__openaiDeveloperDocs__search_openai_docs({query:"Python SDK Responses API structured outputs", limit:5}),
  tools.mcp__openaiDeveloperDocs__fetch_openai_doc({url:"https://developers.openai.com/api/docs/guides/latest-model.md"}),
  tools.mcp__openaiDeveloperDocs__get_openapi_spec({url:"https://api.openai.com/v1/responses", languages:["python"], codeExamplesOnly:true}),
  tools.exec_command({cmd:"git status --short && sed -n '1,240p' README.md && file raw/* && for f in raw/*.pdf; do pdfinfo \"$f\" | sed -n '1,12p'; done","workdir":"/Users/tus/Study/AI_INNOVATION_CHALLENGE/AI-guided-public-service-procedures-Lonely-Stone-","yield_time_ms":10000,"max_output_tokens":20000})
]);
text(JSON.stringify({docs, latest, spec, repo}, null, 2));

